90		async function fetchExec() {
91			if (execLoaded || execLoading) return;
92			execLoading = true;
93			try {
94				const client = createClient();
95				const data = await client.request<{ execution: typeof exec }>(RUN_EXECUTION_QUERY, {
96					id: executionIdFor(runId)
