107		async function fetchSession(sessionId: string) {
108			if (sessionLoaded || sessionLoading) return;
109			sessionLoading = true;
110			try {
111				const client = createClient();
112				const data = await client.request<{ agentSession: SessionDetail | null }>(RUN_SESSION_QUERY, {
113					id: sessionId
114				});
115				session = data.agentSession;
116				sessionLoaded = true;
117			} catch {
118				sessionLoaded = true;
119			} finally {
120				sessionLoading = false;
121			}
122		}
123	
124		async function fetchToolCalls(more = false) {
125			if (toolCallsLoading) return;
126			toolCallsLoading = true;
127			try {
128				const client = createClient();
129				const data = await client.request<{
130					executionToolCalls: {
131						edges: Array<{ node: ToolCall; cursor: string }>;
132						pageInfo: { hasNextPage: boolean; endCursor: string | null };
133						totalCount: number;
134					};
135				}>(RUN_TOOL_CALLS_QUERY, {
136					id: executionIdFor(runId),
137					first: 50,
138					after: more ? toolCallsCursor : null
