140				const newCalls = data.executionToolCalls.edges.map((e) => e.node);
141				toolCalls = more ? [...toolCalls, ...newCalls] : newCalls;
142				toolCallsTotal = data.executionToolCalls.totalCount;
143				toolCallsCursor = data.executionToolCalls.pageInfo.endCursor;
144				toolCallsHasMore = data.executionToolCalls.pageInfo.hasNextPage;
145				toolCallsLoaded = true;
