147				toolCallsLoaded = true;
148			} finally {
149				toolCallsLoading = false;
150			}
151		}
152	
153		$effect(() => {
154			void fetchRun();
155			// run-layer rows correspond to AgentSession invocations
156			if (layer === 'run') {
157				void (async () => {
158					await fetchExec();
159					if (exec?.sessionId) {
