181		const tabs: Array<{ id: Tab; label: string; show: boolean }> = $derived.by(() => {
182			const list: Array<{ id: Tab; label: string; show: boolean }> = [
183				{ id: 'overview', label: 'Overview', show: true }
184			];
185			if (layer !== 'work') {
186				list.push({ id: 'prompt', label: 'Prompt', show: true });
187				list.push({ id: 'response', label: 'Response', show: true });
188			}
189			if (layer === 'run') {
190				list.push({ id: 'session', label: 'Session', show: true });
191			}
192			if (layer === 'run' || layer === 'try') {
193				list.push({ id: 'tools', label: 'Tool calls', show: true });
194			}
195			return list;
196		});
