245						: null}
246				/>
247			{:else if activeTab === 'session'}
248				<Session {session} loading={sessionLoading} sessionId={exec?.sessionId ?? null} />
249			{:else if activeTab === 'tools'}
250				<Tools
251					calls={toolCalls}
252					loading={toolCallsLoading}
253					total={toolCallsTotal}
254					hasMore={toolCallsHasMore}
