180	// readRunBundleFile resolves path under bundleRoot and returns the file's
181	// inline content (when allowed) plus size/truncated metadata. The bool return
182	// is false when the file does not exist (404) or fails the confinement check.
183	func readRunBundleFile(bundleRoot, path string) (*ddxgraphql.RunBundleFileContent, bool) {
184		full, err := resolveRunBundlePath(bundleRoot, path)
185		if err != nil {
186			return nil, false
187		}
188		info, err := os.Stat(full)
189		if err != nil || info.IsDir() {
190			return nil, false
191		}
192		size := int(info.Size())
193		mt := mimeTypeForPath(path)
194		out := &ddxgraphql.RunBundleFileContent{
195			Path:      filepath.ToSlash(path),
196			SizeBytes: size,
197			Truncated: false,
198			MimeType:  mt,
199		}
200		if !runBundleInlineAllowed(path) || size > runBundleInlineMaxBytes {
201			out.Truncated = true
202			return out, true
203		}
204		data, err := os.ReadFile(full)
205		if err != nil {
206			out.Truncated = true
207			return out, true
208		}
209		body := string(data)
210		out.Content = &body
211		return out, true
212	}
