5149	// handleArtifactContent serves the raw file content for a DDx-tracked artifact.
5150	// The artifact is identified by its project-relative path in the "path" query
5151	// parameter. The response Content-Type is inferred from the file extension.
5152	// This endpoint is used by the web UI to render binary artifact types (images,
5153	// PDFs) that cannot be embedded in a GraphQL text response.
5154	func (s *Server) handleArtifactContent(w http.ResponseWriter, r *http.Request) {
5155		entry, ok := projectFromContext(r.Context())
5156		if !ok {
5157			http.Error(w, "project not found", http.StatusNotFound)
5158			return
5159		}
5160	
5161		rawPath := r.URL.Query().Get("path")
5162		if rawPath == "" {
5163			http.Error(w, "path query parameter is required", http.StatusBadRequest)
5164			return
5165		}
5166	
5167		// Normalize and validate path stays within project root.
5168		cleanedPath := filepath.Clean(filepath.FromSlash(rawPath))
5169		if filepath.IsAbs(cleanedPath) || cleanedPath == ".." || strings.HasPrefix(cleanedPath, ".."+string(filepath.Separator)) {
5170			http.Error(w, "invalid path", http.StatusBadRequest)
5171			return
5172		}
5173		absPath := filepath.Join(entry.Path, cleanedPath)
5174		// Double-check the resolved path is under the project root.
5175		rootClean := filepath.Clean(entry.Path) + string(filepath.Separator)
5176		if !strings.HasPrefix(filepath.Clean(absPath)+string(filepath.Separator), rootClean) {
5177			http.Error(w, "invalid path", http.StatusBadRequest)
5178			return
5179		}
5180	
5181		f, err := os.Open(absPath)
5182		if err != nil {
5183			if os.IsNotExist(err) {
5184				http.NotFound(w, r)
5185			} else {
5186				http.Error(w, "failed to read file", http.StatusInternalServerError)
5187			}
5188			return
5189		}
5190		defer f.Close()
5191		info, err := f.Stat()
5192		if err != nil {
5193			http.Error(w, "failed to stat file", http.StatusInternalServerError)
5194			return
5195		}
5196		http.ServeContent(w, r, info.Name(), info.ModTime(), f)
5197	}
